using System.Diagnostics;
using System.Runtime.CompilerServices;
using TextAnalysis;

// Build a representative text corpus (~10k words)
var words = new[] {
    "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
    "lorem", "ipsum", "dolor", "sit", "amet", "consectetur",
    "adipiscing", "elit", "benchmark", "performance", "analysis",
    "extraordinary", "a", "ab", "internationalization"
};
var rng = new Random(42);
var parts = new string[10_000];
for (int i = 0; i < parts.Length; i++)
    parts[i] = words[rng.Next(words.Length)];
var analyzer = new TextAnalyzer(string.Join(' ', parts));

const int warmupIterations = 500;
const int measuredIterations = 5000;

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Warmup: {warmupIterations}  |  Measured: {measuredIterations}");
Console.WriteLine(new string('-', 65));
Console.WriteLine($"{"Method",-25} {"Mean (ns)",12} {"StdDev (ns)",12} {"Median (ns)",12}");
Console.WriteLine(new string('-', 65));

Bench("AverageWordLength", () => analyzer.AverageWordLength());
Bench("WordLengthHistogram", () => analyzer.WordLengthHistogram());
Bench("UniqueWordCount", () => analyzer.UniqueWordCount());

[MethodImpl(MethodImplOptions.NoInlining)]
static void Bench(string name, Action action)
{
    // Warmup
    for (int i = 0; i < warmupIterations; i++) action();

    var timings = new double[measuredIterations];
    var sw = new Stopwatch();
    for (int i = 0; i < measuredIterations; i++)
    {
        sw.Restart();
        action();
        sw.Stop();
        timings[i] = sw.Elapsed.TotalNanoseconds;
    }

    Array.Sort(timings);
    double mean = timings.Average();
    double median = timings[timings.Length / 2];
    double stddev = Math.Sqrt(timings.Select(t => (t - mean) * (t - mean)).Average());

    Console.WriteLine($"{name,-25} {mean,12:F1} {stddev,12:F1} {median,12:F1}");
}

